class Solution {
public:
    bool canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        if ((maxChoosableInteger * (maxChoosableInteger + 1)) / 2 < desiredTotal) return false;
        vector<bool> used(maxChoosableInteger + 1, false);
        return dfs(0, desiredTotal, used, maxChoosableInteger);
    }

    bool dfs(int curr, int total, vector<bool>& used, int maxChoosableInteger) {
        if (total <= 0) return true;
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if (used[i]) continue;
            used[i] = true;
            if (!dfs(curr + i, total - i, used, maxChoosableInteger)) {
                used[i] = false;
                return true;
            }
            used[i] = false;
        }
        return false;
    }
};
